import sys

def solve():
    input_data = sys.stdin.read().split()
    n = int(input_data[0])
    a = list(map(int, input_data[1:n+1]))
    l, r = 0, n-1
    last = -1
    moves = 0
    while l <= r:
        can_l = a[l] > last
        can_r = a[r] > last
        if can_l and can_r:
            if a[l] <= a[r]:
                last = a[l]; l += 1
            else:
                last = a[r]; r -= 1
        elif can_l:
            last = a[l]; l += 1
        elif can_r:
            last = a[r]; r -= 1
        else:
            break
        moves += 1
    print("Alice" if moves % 2 == 1 else "Bob")

solve()

import sys
from functools import lru_cache
input = sys.stdin.readline

def solve():
    n = int(input())
    A = list(map(int, input().split()))

    @lru_cache(maxsize=None)
    def dp(l, r, last):
        if l > r:
            return 0
        best = 0
        if A[l] > last:
            best = max(best, 1 + dp(l+1, r, A[l]))
        if A[r] > last:
            best = max(best, 1 + dp(l, r-1, A[r]))
        return best

    total = dp(0, n-1, -1)
    print("Alice" if total % 2 == 1 else "Bob")

solve()

